import type { ColorRuleProps } from '../types/color-rule.js';

/**
 * @public
 */
export const ColorRule = (_props: ColorRuleProps) => null;

ColorRule['displayName'] = 'ColorRule';

export const isValidColorRule = (props: ColorRuleProps): boolean => {
  const keys = Object.keys(props);

  return (
    keys.includes('comparator') &&
    keys.includes('matchValue') &&
    (keys.includes('color') || keys.includes('colorPalette'))
  );
};
